Code.Terraform:
```hcl
# 确保复制集存在并变为 ACTIVE
resource "aws_ssmincidents_replication_set" "example" {
  regions {                      # 关键：创建复制集，使其能够处于 ACTIVE 状态
    region_name = "us-east-1"
  }
}

# 创建一个最小化的响应计划
resource "aws_ssmincidents_response_plan" "example" {
  name = "<example_resource_name>"  # 关键：确保至少存在一个响应计划

  incident_template {                # 关键：必需 template for the plan
    title  = "<example_title>"
    impact = 5
  }
}
```
